import urllib.request, json, urllib.parse
for phrase in ["\"post-behavioral change\"", "\"greatest change in fluorescence\""]:
    print(f"Searching for {phrase}...")
    query = urllib.parse.quote(phrase)
    url = f"https://www.ebi.ac.uk/europepmc/webservices/rest/search?query={query}&format=json&resultType=core"
    try:
        req = urllib.request.urlopen(url)
        res = json.loads(req.read().decode())
        for r in res.get("resultList", {}).get("result", []):
            print("Title:", r.get("title"))
            print("PMCID:", r.get("pmcid"))
    except Exception as e:
        print(e)
